//! Dispatch for `Expression::ExtraBuiltinFunctionCall` — layout helper
//! functions generated by the LLR's layout lowering pass.

use crate::Value;
use crate::eval::{EvalContext, eval_expression};
use i_slint_compiler::llr::Expression;
use i_slint_core::SharedVector;
use i_slint_core::layout::{
    BoxLayoutData, FlexboxLayoutData, FlexboxLayoutItemInfo, GridLayoutData, GridLayoutInputData,
    LayoutInfo, LayoutItemInfo, Padding,
};
use i_slint_core::model::Model;
use i_slint_core::slice::Slice;

// ── Value → layout-type converters ──────────────────────────────────────────

fn to_f32(v: &Value) -> f32 {
    match v {
        Value::Number(n) => *n as f32,
        _ => 0.,
    }
}

fn to_padding(v: &Value) -> Padding {
    let Value::Struct(s) = v else { return Padding::default() };
    let f = |k| match s.get_field(k) {
        Some(Value::Number(n)) => *n as f32,
        _ => 0.,
    };
    Padding { begin: f("begin"), end: f("end") }
}

fn to_enum<T: std::str::FromStr + Default>(v: &Value) -> T {
    match v {
        Value::EnumerationValue(_, n) => n.parse().unwrap_or_default(),
        _ => T::default(),
    }
}

fn to_cells(v: &Value) -> Vec<LayoutItemInfo> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            let c = s.get_field("constraint")?;
            Some(LayoutItemInfo { constraint: c.clone().try_into().unwrap_or_default() })
        })
        .collect()
}

/// Convert one `Value::Struct` produced by the LLR's flexbox lowering.
/// `Struct::get_field` normalizes identifiers, so the kebab-case keys the
/// lowering emits match regardless of spelling.
pub(crate) fn flexbox_item_info_from_struct(s: &crate::api::Struct) -> FlexboxLayoutItemInfo {
    let f = |k: &str| -> f32 {
        match s.get_field(k) {
            Some(Value::Number(n)) => *n as f32,
            _ => 0.,
        }
    };
    let constraint: LayoutInfo =
        s.get_field("constraint").cloned().and_then(|v| v.try_into().ok()).unwrap_or_default();
    // An absent flex-basis means auto (-1 like core's Default); an
    // explicit 0 must pass through, it requests a zero base size.
    let flex_basis = match s.get_field("flex-basis") {
        Some(Value::Number(n)) => *n as f32,
        _ => -1.,
    };
    FlexboxLayoutItemInfo {
        constraint,
        flex_grow: f("flex-grow"),
        flex_shrink: f("flex-shrink"),
        flex_basis,
        flex_align_self: s.get_field("flex-align-self").map(to_enum).unwrap_or_default(),
        flex_order: match s.get_field("flex-order") {
            Some(Value::Number(n)) => *n as i32,
            _ => 0,
        },
    }
}

fn to_flex_cells(v: &Value) -> Vec<FlexboxLayoutItemInfo> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            Some(flexbox_item_info_from_struct(&s))
        })
        .collect()
}

fn to_u32_vec(v: &Value) -> Vec<u32> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| match m.row_data(i)? {
            Value::Number(n) => Some(n as u32),
            _ => None,
        })
        .collect()
}

fn to_grid_input_data(v: &Value) -> Vec<GridLayoutInputData> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| {
            let Value::Struct(s) = m.row_data(i)? else { return None };
            let f = |k: &str| match s.get_field(k) {
                Some(Value::Number(n)) => *n as f32,
                _ => 0.,
            };
            Some(GridLayoutInputData {
                new_row: matches!(s.get_field("new_row"), Some(Value::Bool(true))),
                col: f("col"),
                row: f("row"),
                colspan: f("colspan"),
                rowspan: f("rowspan"),
            })
        })
        .collect()
}

fn to_array_of_u16(v: &Value) -> SharedVector<u16> {
    match v {
        Value::ArrayOfU16(v) => v.clone(),
        _ => Default::default(),
    }
}

fn to_dialog_roles(v: &Value) -> Vec<i_slint_core::items::DialogButtonRole> {
    let Value::Model(m) = v else { return Vec::new() };
    (0..m.row_count())
        .filter_map(|i| match m.row_data(i)? {
            Value::EnumerationValue(_, n) => n.parse().ok(),
            _ => None,
        })
        .collect()
}

fn sf32(s: &crate::api::Struct, k: &str) -> f32 {
    match s.get_field(k) {
        Some(Value::Number(n)) => *n as f32,
        _ => 0.,
    }
}

// ── Dispatch ────────────────────────────────────────────────────────────────

pub(crate) fn call_extra_builtin(
    ctx: &mut EvalContext,
    name: &str,
    arguments: &[Expression],
) -> Value {
    let a: Vec<Value> = arguments.iter().map(|e| eval_expression(ctx, e)).collect();

    match name {
        "box_layout_info" => {
            let c = to_cells(&a[0]);
            i_slint_core::layout::box_layout_info(
                Slice::from_slice(&c),
                to_f32(&a[1]),
                &to_padding(&a[2]),
                to_enum(&a[3]),
            )
            .into()
        }
        "box_layout_info_ortho" => {
            let c = to_cells(&a[0]);
            i_slint_core::layout::box_layout_info_ortho(Slice::from_slice(&c), &to_padding(&a[1]))
                .into()
        }
        "organize_dialog_button_layout" => {
            let input = to_grid_input_data(&a[0]);
            let roles = to_dialog_roles(&a[1]);
            Value::ArrayOfU16(i_slint_core::layout::organize_dialog_button_layout(
                Slice::from_slice(&input),
                Slice::from_slice(&roles),
            ))
        }
        "organize_grid_layout" => {
            let (input, ri, rs) = (to_grid_input_data(&a[0]), to_u32_vec(&a[1]), to_u32_vec(&a[2]));
            Value::ArrayOfU16(i_slint_core::layout::organize_grid_layout(
                Slice::from_slice(&input),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
            ))
        }
        "grid_layout_info" => {
            let (c, ri, rs) = (to_cells(&a[1]), to_u32_vec(&a[2]), to_u32_vec(&a[3]));
            i_slint_core::layout::grid_layout_info(
                to_array_of_u16(&a[0]),
                Slice::from_slice(&c),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
                to_f32(&a[4]),
                &to_padding(&a[5]),
                to_enum(&a[6]),
            )
            .into()
        }
        "solve_grid_layout" => {
            let (c, ri, rs) = (to_cells(&a[1]), to_u32_vec(&a[3]), to_u32_vec(&a[4]));
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            Value::LayoutCache(i_slint_core::layout::solve_grid_layout(
                &GridLayoutData {
                    size: sf32(s, "size"),
                    spacing: sf32(s, "spacing"),
                    padding: s.get_field("padding").map(to_padding).unwrap_or_default(),
                    organized_data: s
                        .get_field("organized_data")
                        .map(to_array_of_u16)
                        .unwrap_or_default(),
                },
                Slice::from_slice(&c),
                to_enum(&a[2]),
                Slice::from_slice(&ri),
                Slice::from_slice(&rs),
            ))
        }
        "solve_box_layout" => {
            let ri = to_u32_vec(&a[1]);
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            let cells = s.get_field("cells").map(to_cells).unwrap_or_default();
            Value::LayoutCache(i_slint_core::layout::solve_box_layout(
                &BoxLayoutData {
                    size: sf32(s, "size"),
                    spacing: sf32(s, "spacing"),
                    padding: s.get_field("padding").map(to_padding).unwrap_or_default(),
                    alignment: s.get_field("alignment").map(to_enum).unwrap_or_default(),
                    cells: Slice::from_slice(&cells),
                },
                Slice::from_slice(&ri),
            ))
        }
        "solve_box_layout_ortho" => {
            let ri = to_u32_vec(&a[1]);
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            let cells = s.get_field("cells").map(to_cells).unwrap_or_default();
            Value::LayoutCache(i_slint_core::layout::solve_box_layout_ortho(
                &i_slint_core::layout::BoxLayoutOrthoData {
                    size: sf32(s, "size"),
                    padding: s.get_field("padding").map(to_padding).unwrap_or_default(),
                    cross_axis_alignment: s
                        .get_field("cross_axis_alignment")
                        .map(to_enum)
                        .unwrap_or_default(),
                    cells: Slice::from_slice(&cells),
                },
                Slice::from_slice(&ri),
            ))
        }
        "solve_flexbox_layout" => {
            let ri = to_u32_vec(&a[1]);
            let Value::Struct(s) = &a[0] else { return Value::LayoutCache(Default::default()) };
            let (ch, cv) = (
                s.get_field("cells_h").map(to_flex_cells).unwrap_or_default(),
                s.get_field("cells_v").map(to_flex_cells).unwrap_or_default(),
            );
            Value::LayoutCache(i_slint_core::layout::solve_flexbox_layout(
                &FlexboxLayoutData {
                    width: sf32(s, "width"),
                    height: sf32(s, "height"),
                    spacing_h: sf32(s, "spacing_h"),
                    spacing_v: sf32(s, "spacing_v"),
                    padding_h: s.get_field("padding_h").map(to_padding).unwrap_or_default(),
                    padding_v: s.get_field("padding_v").map(to_padding).unwrap_or_default(),
                    alignment: s.get_field("alignment").map(to_enum).unwrap_or_default(),
                    direction: s.get_field("direction").map(to_enum).unwrap_or_default(),
                    align_content: s.get_field("align_content").map(to_enum).unwrap_or_default(),
                    cross_axis_alignment: s
                        .get_field("cross_axis_alignment")
                        .map(to_enum)
                        .unwrap_or_default(),
                    flex_wrap: s.get_field("flex_wrap").map(to_enum).unwrap_or_default(),
                    cells_h: Slice::from_slice(&ch),
                    cells_v: Slice::from_slice(&cv),
                },
                Slice::from_slice(&ri),
            ))
        }
        "flexbox_layout_info_main_axis" => {
            let cells = to_flex_cells(&a[0]);
            i_slint_core::layout::flexbox_layout_info_main_axis(
                Slice::from_slice(&cells),
                to_f32(&a[1]),
                &to_padding(&a[2]),
                to_enum(&a[3]),
            )
            .into()
        }
        "flexbox_layout_unwrapped_main" => {
            let cells = to_flex_cells(&a[0]);
            Value::Number(i_slint_core::layout::flexbox_layout_unwrapped_main(
                Slice::from_slice(&cells),
                to_f32(&a[1]),
                &to_padding(&a[2]),
            ) as f64)
        }
        "flexbox_layout_info_cross_axis" => {
            let (ch, cv) = (to_flex_cells(&a[0]), to_flex_cells(&a[1]));
            i_slint_core::layout::flexbox_layout_info_cross_axis(
                Slice::from_slice(&ch),
                Slice::from_slice(&cv),
                to_f32(&a[2]),
                to_f32(&a[3]),
                &to_padding(&a[4]),
                &to_padding(&a[5]),
                to_enum(&a[6]),
                to_enum(&a[7]),
                to_f32(&a[8]),
            )
            .into()
        }
        other => unimplemented!("ExtraBuiltinFunctionCall `{other}`"),
    }
}

/// Interpret [`Expression::SolveFlexboxLayoutWithMeasure`].
///
/// Mirrors the rust generator: taffy calls the measure callback with exactly
/// one of width/height known (the cross axis); we then re-evaluate that
/// cell's perpendicular layout info with the `measure_known_w` /
/// `measure_known_h` local set to the assigned dimension. Cells without a
/// known cross-axis size fall back to the `default_cells` preferred size.
pub(crate) fn solve_flexbox_layout_with_measure(ctx: &mut EvalContext, expr: &Expression) -> Value {
    let Expression::SolveFlexboxLayoutWithMeasure {
        data,
        repeater_indices,
        measure_cells,
        default_cells,
        cells_variables,
    } = expr
    else {
        return Value::Void;
    };
    let ri = to_u32_vec(&eval_expression(ctx, repeater_indices));
    let data = eval_expression(ctx, data);
    let Value::Struct(s) = &data else { return Value::LayoutCache(Default::default()) };
    let (ch, cv) = (
        s.get_field("cells_h").map(to_flex_cells).unwrap_or_default(),
        s.get_field("cells_v").map(to_flex_cells).unwrap_or_default(),
    );

    let eval_info = |ctx: &mut EvalContext, e: &Expression| -> LayoutInfo {
        eval_expression(ctx, e).try_into().unwrap_or_default()
    };

    // Flatten `measure_cells` into one entry per taffy cell. Static cells carry
    // their `(h_info, v_info)` expressions; a repeater expands to one instance
    // per row (re-measured through its own item tree at the assigned cross size).
    // When there is no repeater (`cells_variables` is `None`) this is exactly
    // `measure_cells`, and the per-cell defaults come from `default_cells`;
    // otherwise the defaults come from the flat `cells_h`/`cells_v` arrays.
    enum FlatCell<'a> {
        Static(&'a Expression, &'a Expression),
        Repeated(vtable::VRc<i_slint_core::item_tree::ItemTreeVTable, crate::instance::Instance>),
    }
    let mut flat: Vec<FlatCell> = Vec::with_capacity(measure_cells.len());
    for item in measure_cells {
        match item {
            itertools::Either::Left((h_info, v_info)) => {
                flat.push(FlatCell::Static(h_info, v_info))
            }
            itertools::Either::Right(repeater) => {
                if let Some(current) = ctx.current.as_ref() {
                    let rep = &current.repeaters[repeater.repeater_index];
                    rep.track_instance_changes();
                    flat.extend(rep.instances_vec().into_iter().map(FlatCell::Repeated));
                }
            }
        }
    }

    // Preferred (default-constraint) size per cell, used when taffy asks for a
    // dimension without a known cross-axis size. With a repeater, read the flat
    // cell arrays (which include the expanded instances); otherwise evaluate the
    // per-element `default_cells`.
    let (mut pref_w, mut pref_h) = (Vec::new(), Vec::new());
    if cells_variables.is_some() {
        pref_w.extend(ch.iter().map(|c| c.constraint.preferred_bounded()));
        pref_h.extend(cv.iter().map(|c| c.constraint.preferred_bounded()));
    } else {
        for item in default_cells {
            if let itertools::Either::Left((h_info, v_info)) = item {
                pref_w.push(eval_info(ctx, h_info).preferred_bounded());
                pref_h.push(eval_info(ctx, v_info).preferred_bounded());
            }
        }
    }

    let mut measure = |index: usize, known_w: Option<f32>, known_h: Option<f32>| -> (f32, f32) {
        let w = known_w.unwrap_or_else(|| pref_w.get(index).copied().unwrap_or(0f32));
        let h = known_h.unwrap_or_else(|| pref_h.get(index).copied().unwrap_or(0f32));
        match (known_w.is_some() && known_h.is_none(), flat.get(index)) {
            (true, Some(FlatCell::Static(_, v_info))) => {
                ctx.locals.insert("measure_known_w".into(), Value::Number(w as f64));
                return (w, eval_info(ctx, v_info).preferred_bounded());
            }
            (true, Some(FlatCell::Repeated(instance))) => {
                let nh = instance
                    .as_pin_ref()
                    .flexbox_layout_item_info_at_cross_width(w)
                    .constraint
                    .preferred_bounded();
                return (w, nh);
            }
            _ => {}
        }
        if known_h.is_some()
            && known_w.is_none()
            && let Some(FlatCell::Static(h_info, _)) = flat.get(index)
        {
            ctx.locals.insert("measure_known_h".into(), Value::Number(h as f64));
            let nw = eval_info(ctx, h_info).preferred_bounded();
            return (nw, h);
        }
        (w, h)
    };

    Value::LayoutCache(i_slint_core::layout::solve_flexbox_layout_with_measure(
        &FlexboxLayoutData {
            width: sf32(s, "width"),
            height: sf32(s, "height"),
            spacing_h: sf32(s, "spacing_h"),
            spacing_v: sf32(s, "spacing_v"),
            padding_h: s.get_field("padding_h").map(to_padding).unwrap_or_default(),
            padding_v: s.get_field("padding_v").map(to_padding).unwrap_or_default(),
            alignment: s.get_field("alignment").map(to_enum).unwrap_or_default(),
            direction: s.get_field("direction").map(to_enum).unwrap_or_default(),
            align_content: s.get_field("align_content").map(to_enum).unwrap_or_default(),
            cross_axis_alignment: s
                .get_field("cross_axis_alignment")
                .map(to_enum)
                .unwrap_or_default(),
            flex_wrap: s.get_field("flex_wrap").map(to_enum).unwrap_or_default(),
            cells_h: Slice::from_slice(&ch),
            cells_v: Slice::from_slice(&cv),
        },
        Slice::from_slice(&ri),
        Some(&mut measure),
    ))
}
